"use client"

import { NimbleSidebar } from "@/components/nimble-sidebar"
import { NimbleHeader } from "@/components/nimble-header"

interface ShellLayoutProps {
  children: React.ReactNode
  currentPath?: string
  pageTitle?: string
}

export function ShellLayout({ children, currentPath = "/", pageTitle = "Dashboard" }: ShellLayoutProps) {
  return (
    <div className="flex h-screen bg-background">
      <NimbleSidebar currentPath={currentPath} />
      <div className="flex-1 flex flex-col overflow-hidden">
        <NimbleHeader pageTitle={pageTitle} />
        <main className="flex-1 overflow-auto p-6">
          {children}
        </main>
      </div>
    </div>
  )
}
